import java.util.HashMap;import java.util.Map;// Room classclass Room {    int beds;    int size;    int price;    public Room(int beds, int size, int price) {        this.beds = beds;        this.size = size;        this.price = price;    }}// RoomInventory classclass RoomInventory {    private Map<String, Integer> rooms;    public RoomInventory() {        rooms = new HashMap<>();        rooms.put("Single", 10);        rooms.put("Double", 5);        rooms.put("Suite", 2);    }    public Map<String, Integer> getRoomAvailability() {        return rooms;    }}// Main classpublic class BookMyStayApp {    public static void main(String[] args) {        RoomInventory inventory = new RoomInventory();        Map<String, Integer> availability = inventory.getRoomAvailability();        System.out.println("Room Availability:");        System.out.println("Single Room: " + availability.get("Single"));        System.out.println("Double Room: " + availability.get("Double"));        System.out.println("Suite Room: " + availability.get("Suite"));    }}